<?php
namespace Tests\Feature;
use App\Models\Character;use App\Models\User;use App\Models\World;use Database\Seeders\CharacterLevelRequirementSeeder;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class GameNavigationTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(CharacterLevelRequirementSeeder::class);}private function player(){$u=User::factory()->create();$c=Character::factory()->for($u)->create();return[$u,$c];}private function assertGlobal($response){return$response->assertSee('Inicio')->assertSee('Mi personaje')->assertSee('Mundo')->assertSee('Cerrar sesión')->assertDontSee('Add Product')->assertDontSee('Reports')->assertDontSee('404 Error');}public function test_global_and_contextual_navigation_states(){list($u,$c)=$this->player();$this->actingAs($u);$this->assertGlobal($this->get(route('dashboard')))->assertOk();$this->assertGlobal($this->get(route('characters.show',$c)))->assertSee('nav-link active" href="'.route('characters.show',$c),false)->assertSee('Resumen y estadísticas');$this->assertGlobal($this->get(route('characters.inventory.index',$c)))->assertSee('nav-link active" href="'.route('characters.inventory.index',$c),false)->assertSee('Volver al personaje');$this->assertGlobal($this->get(route('characters.wallet.show',$c)))->assertSee('nav-link active" href="'.route('characters.wallet.show',$c),false)->assertSee('Volver al personaje');}public function test_world_navigation_and_breadcrumbs(){list($u,$c)=$this->player();$this->seed(WorldCatalogSeeder::class);$world=World::where('code','eldoria')->firstOrFail();$region=$world->regions()->firstOrFail();$zone=$region->zones()->firstOrFail();$response=$this->actingAs($u)->get(route('zones.show',$zone));$this->assertGlobal($response)->assertOk()->assertSeeInOrder(['Inicio','Mundo',$world->name,$region->name,$zone->name])->assertDontSee('Resumen y estadísticas');}public function test_links_never_use_another_character(){list($u,$c)=$this->player();$other=Character::factory()->for(User::factory())->create();$this->actingAs($u)->get(route('characters.show',$c))->assertSee(route('characters.show',$c),false)->assertDontSee(route('characters.show',$other),false);$this->get(route('characters.show',$other))->assertForbidden();}public function test_guest_remains_blocked(){list($u,$c)=$this->player();$this->get(route('characters.inventory.index',$c))->assertRedirect('/login');}}
